+fn frame_spec_may_observe_change_tracking(frame: &FrameSpec) -> bool {
+    frame_bound_may_observe_change_tracking(&frame.start)
+        || frame
+            .end
+            .as_ref()
+            .is_some_and(frame_bound_may_observe_change_tracking)
+}
+
+fn frame_bound_may_observe_change_tracking(bound: &FrameBound) -> bool {
+    match bound {
+        FrameBound::Preceding(expr) | FrameBound::Following(expr) => {
+            expr_may_observe_change_tracking(expr)
+        }
+        FrameBound::UnboundedPreceding
+        | FrameBound::CurrentRow
+        | FrameBound::UnboundedFollowing => false,
+    }
+}
+
+fn function_name_observes_change_tracking(name: &str) -> bool {
+    matches!(
+        name.to_ascii_lowercase().as_str(),
+        "changes" | "total_changes" | "last_insert_rowid"
+    )
+}
+
+fn expr_may_observe_change_tracking(expr: &Expr) -> bool {
+    match expr {
+        Expr::FunctionCall {
+            name,
+            args,
+            order_by,
+            filter,
+            over,
+            ..
+        } => {
+            function_name_observes_change_tracking(name)
+                || match args {
+                    FunctionArgs::List(exprs) => exprs.iter().any(expr_may_observe_change_tracking),
+                    FunctionArgs::Star => false,
+                }
+                || order_by
+                    .iter()
+                    .any(|term| expr_may_observe_change_tracking(&term.expr))
+                || filter
+                    .as_deref()
+                    .is_some_and(expr_may_observe_change_tracking)
+                || over
+                    .as_ref()
+                    .is_some_and(window_spec_may_observe_change_tracking)
+        }
+        Expr::BinaryOp { left, right, .. } => {
+            expr_may_observe_change_tracking(left) || expr_may_observe_change_tracking(right)
+        }
+        Expr::UnaryOp { expr, .. }
+        | Expr::Cast { expr, .. }
+        | Expr::Collate { expr, .. }
+        | Expr::IsNull { expr, .. } => expr_may_observe_change_tracking(expr),
+        Expr::Between {
+            expr, low, high, ..
+        } => {
+            expr_may_observe_change_tracking(expr)
+                || expr_may_observe_change_tracking(low)
+                || expr_may_observe_change_tracking(high)
+        }
+        Expr::In { expr, set, .. } => {
+            expr_may_observe_change_tracking(expr)
+                || match set {
+                    InSet::List(values) => values.iter().any(expr_may_observe_change_tracking),
+                    InSet::Subquery(query) => select_may_observe_change_tracking(query),
+                    InSet::Table(_) => false,
+                }
+        }
+        Expr::Like {
+            expr,
+            pattern,
+            escape,
+            ..
+        } => {
+            expr_may_observe_change_tracking(expr)
+                || expr_may_observe_change_tracking(pattern)
+                || escape
+                    .as_deref()
+                    .is_some_and(expr_may_observe_change_tracking)
+        }
+        Expr::Case {
+            operand,
+            whens,
+            else_expr,
+            ..
+        } => {
+            operand
+                .as_deref()
+                .is_some_and(expr_may_observe_change_tracking)
+                || whens.iter().any(|(when_expr, then_expr)| {
+                    expr_may_observe_change_tracking(when_expr)
+                        || expr_may_observe_change_tracking(then_expr)
+                })
+                || else_expr
+                    .as_deref()
+                    .is_some_and(expr_may_observe_change_tracking)
+        }
+        Expr::Exists { subquery, .. } | Expr::Subquery(subquery, _) => {
+            select_may_observe_change_tracking(subquery)
+        }
+        Expr::JsonAccess { expr, path, .. } => {
+            expr_may_observe_change_tracking(expr) || expr_may_observe_change_tracking(path)
+        }
+        Expr::RowValue(values, _) => values.iter().any(expr_may_observe_change_tracking),
+        Expr::Literal(_, _) | Expr::Column(_, _) | Expr::Placeholder(_, _) | Expr::Raise { .. } => {
+            false
+        }
+    }
+}
